function Card({character, onClose }) {
  const {id, name, species,gender, image} = character
  return (
    <div>
      <button
        onClick={() => {
          onClose(id);
        }}
      >
        X
      </button>
      <h2>{name}</h2>
      <h2>{character.species}</h2>
      <h2>{character.gender}</h2>
      <img src={image} alt={name} />
    </div>
  );
}

export default Card;
